CREATE TABLE IF NOT EXISTS soft_skills (
    id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    nome TEXT UNIQUE NOT NULL,
    explicacao TEXT,
    modelo_analise TEXT
);

-- Habilita RLS por padrão
ALTER TABLE soft_skills ENABLE ROW LEVEL SECURITY;

-- Permite leitura pública (mesmo padrão dos outros dicionários como arcanos, kans)
CREATE POLICY "Permitir leitura publica de dicionarios" ON soft_skills FOR SELECT USING (true);

-- Popula os dados
ON CONFLICT (nome) DO UPDATE SET 
    explicacao = EXCLUDED.explicacao,
    modelo_analise = EXCLUDED.modelo_analise;
